<!DOCTYPE html>
<html lang="id">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <meta name="description" content="Tifanny">
    <title>{{ $title ?? 'Tifanny ERP Commerce' }}</title>
    <link href="https://fonts.googleapis.com/css2?family=Poppins:wght@400;500;600;700;800;900&family=Inter:wght@400;500;600;700&display=swap" rel="stylesheet">
    <script src="https://cdn.jsdelivr.net/npm/chart.js"></script>
    <style>
        :root{--primary:#FFB26B;--primary-dark:#F59340;--primary-light:#FFD4A3;--secondary:#FFF8F0;--dark:#393053;--dark2:#2A2240;--gray-100:#F5F5F5;--gray-200:#EAEAEA;--gray-400:#AAAAAA;--gray-600:#666;--gray-800:#333;--success:#22C55E;--warning:#F59E0B;--danger:#EF4444;--info:#3B82F6;--radius:16px;--shadow:0 8px 40px rgba(0,0,0,.12)}
        *{box-sizing:border-box}body{margin:0;background:var(--gray-100);font-family:Inter,sans-serif;color:var(--gray-800)}a{text-decoration:none;color:inherit}.font-poppins{font-family:Poppins,sans-serif}.btn{display:inline-flex;gap:8px;align-items:center;justify-content:center;border:0;border-radius:10px;padding:10px 16px;font-weight:700;cursor:pointer}.btn-primary{background:var(--primary);color:var(--dark)}.btn-dark{background:var(--dark);color:white}.btn-outline{border:1px solid var(--gray-200);background:white;color:var(--dark)}.container{max-width:1180px;margin:auto;padding:0 20px}.nav{height:66px;background:rgba(255,255,255,.94);backdrop-filter:blur(20px);border-bottom:1px solid var(--gray-200);position:sticky;top:0;z-index:50}.nav-inner{height:66px;display:flex;align-items:center;gap:28px}.logo{font-family:Poppins,sans-serif;font-size:23px;font-weight:900;color:var(--dark)}.logo span{color:var(--primary-dark)}.nav-links{margin-left:auto;display:flex;gap:18px;align-items:center;font-size:14px;font-weight:600;color:var(--gray-600)}.hero{background:linear-gradient(135deg,var(--secondary),#FFE8CC,#FFF3E0);padding:85px 0}.hero-grid{display:grid;grid-template-columns:1.2fr .8fr;gap:48px;align-items:center}.hero h1{font-family:Poppins,sans-serif;font-size:clamp(42px,6vw,72px);line-height:1.05;margin:0;color:var(--dark);font-weight:900}.hero h1 span{color:var(--primary-dark)}.hero p{font-size:18px;line-height:1.8;color:var(--gray-600);max-width:560px}.hero-emoji{font-size:160px;background:linear-gradient(145deg,var(--primary-light),var(--primary));width:330px;height:330px;border-radius:50%;display:flex;align-items:center;justify-content:center;box-shadow:0 20px 60px rgba(255,178,107,.45);margin:auto}.section{padding:60px 0}.section-title{font-family:Poppins,sans-serif;font-size:34px;color:var(--dark);font-weight:900;margin:0 0 22px}.grid{display:grid;gap:20px}.grid-3{grid-template-columns:repeat(3,minmax(0,1fr))}.grid-4{grid-template-columns:repeat(4,minmax(0,1fr))}.card{background:white;border:1px solid var(--gray-200);border-radius:var(--radius);padding:22px;box-shadow:0 2px 8px rgba(0,0,0,.04)}.product{transition:.2s}.product:hover{transform:translateY(-3px);box-shadow:var(--shadow)}.product-img{height:165px;border-radius:14px;background:linear-gradient(145deg,var(--secondary),#FFE8CC);font-size:76px;display:flex;align-items:center;justify-content:center;margin-bottom:18px}.price{font-family:Poppins,sans-serif;color:var(--primary-dark);font-weight:900;font-size:24px}.app{display:flex;min-height:100vh}.sidebar{width:260px;background:var(--dark);color:white;position:fixed;inset:0 auto 0 0;padding:18px 12px;overflow:auto}.sidebar .brand{font-family:Poppins,sans-serif;font-weight:900;font-size:20px;padding:8px 10px 18px}.sidebar .brand span{color:var(--primary)}.menu-label{font-size:10px;color:rgba(255,255,255,.35);font-weight:800;text-transform:uppercase;letter-spacing:1.4px;margin:18px 10px 8px}.menu a{display:flex;gap:10px;padding:11px 12px;border-radius:10px;color:rgba(255,255,255,.72);font-weight:700;font-size:14px}.menu a:hover,.menu a.active{background:var(--primary);color:var(--dark)}.main{margin-left:260px;flex:1}.topbar{height:66px;background:white;border-bottom:1px solid var(--gray-200);display:flex;align-items:center;padding:0 26px;position:sticky;top:0;z-index:20}.content{padding:28px}.stat .num{font-family:Poppins,sans-serif;font-size:28px;font-weight:900;color:var(--dark)}.stat .label{font-size:13px;color:var(--gray-400);margin-top:6px}.badge{display:inline-flex;padding:5px 10px;border-radius:999px;font-size:12px;font-weight:800}.badge-success{background:rgba(34,197,94,.12);color:#15803D}.badge-danger{background:rgba(239,68,68,.12);color:#DC2626}.badge-warning{background:rgba(245,158,11,.14);color:#D97706}.table{width:100%;border-collapse:collapse}.table th{background:var(--gray-100);font-size:12px;text-transform:uppercase;letter-spacing:.5px;color:var(--gray-400);text-align:left;padding:13px}.table td{padding:14px 13px;border-bottom:1px solid var(--gray-200);font-size:14px}.alert{border-radius:14px;padding:14px 18px;margin-bottom:20px}.alert-danger{background:rgba(239,68,68,.08);border:1px solid rgba(239,68,68,.2);color:#b91c1c}.alert-success{background:rgba(34,197,94,.10);border:1px solid rgba(34,197,94,.22);color:#15803d}.pos-layout{display:grid;grid-template-columns:1fr 380px;gap:20px}.pos-products{display:grid;grid-template-columns:repeat(auto-fill,minmax(160px,1fr));gap:12px}.pos-card{text-align:center;cursor:pointer}.pos-card:hover{border-color:var(--primary);box-shadow:var(--shadow)}.cart-item{display:flex;gap:10px;align-items:center;border:1px solid var(--gray-200);background:var(--gray-100);border-radius:12px;padding:10px;margin-bottom:8px}.cart-item button{border:0;background:var(--primary);border-radius:50%;width:24px;height:24px;font-weight:900}.form-control{width:100%;padding:10px 12px;border:1px solid var(--gray-200);border-radius:10px;font:inherit}@media(max-width:900px){.grid-3,.grid-4,.hero-grid,.pos-layout{grid-template-columns:1fr}.sidebar{position:static;width:auto}.main{margin-left:0}.app{display:block}.nav-links{display:none}.hero-emoji{display:none}}
    </style>
</head>
<body>
    @yield('body')
</body>
</html>
